module top_module(input [15:0] input_value, input [1:0] signextsignal, output [31:0] y);reg [31:0] r;
	always@(*)
		case(signextsignal)
			2'b00: r = {{16{input_value[15]}},input_value};
			2'b10: r = {16'b0, input_value};
			2'b11: r = {16'b1111111111111111, input_value};
			default : r = {{16{input_value[15]}},input_value};
		endcase

	assign y = r;

endmodule
